# Move event indexes and labels extracted from G_19_move_events.csv
move_indexes = [(307, 'auth-service'), (333, 'gateway'), (364, 'user-service')]

fig, ax = plt.subplots(figsize=(12, 6))

# Plot the continuous latency line
ax.plot(range(len(latencies)), latencies, color="#2563eb", linewidth=1.5, label="End-to-End Latency")

# Plot vertical dashed lines for move events
colors = ["#f59e0b", "#d97706", "#b45309", "#ea580c", "#c2410c"]
for i, (idx, src) in enumerate(move_indexes):
    c = colors[i % len(colors)]
    ax.axvline(x=idx, color=c, linestyle="--", linewidth=1.5, label=f"{src} moved")

ax.set_ylabel("Latency (ms)")
ax.set_xlabel("Request Number (Time Sequence)")
ax.set_title("Load Generator End-to-End Latency over Time")
ax.grid(True, linestyle=":", alpha=0.6)
ax.legend()

